package basics_01;

public class Arithmeticdemo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=30;
		int b=25;
		System.out.println("sum:"+(a+b));
		System.out.println("diff:"+(a-b));
		System.out.println("mul:"+(a*b));
		System.out.println("div:"+(a%b));
		

	}

}
